#include <iostream>
#include <string>
#include <string_view>

class Animal
{
    std::string m_name;

public:
    Animal(const std::string& name)
        : m_name{ name }
    {
    }

    const std::string& getName() const { return m_name; }
    std::string_view speak() const { return "..."; }
};

class Cat : public Animal
{
public:
    Cat(const std::string& name)
        : Animal{ name }
    {
    }

    std::string_view speak() const { return "Meow"; }
};

class Dog : public Animal
{
public:
    Dog(const std::string& name)
        : Animal{ name }
    {
    }

    std::string_view speak() const { return "Woof"; }
};

int main()
{
    int n{};
    std::cin >> n;

    for (int i{ 0 }; i < n; ++i)
    {
        std::string type{};
        std::string name{};
        std::cin >> type >> name;

        if (type == "cat")
        {
            Cat cat{ name };
            const Animal& ref{ cat };
            std::cout << cat.getName() << ": direct=" << cat.speak()
                      << " ref=" << ref.speak() << '\n';
        }
        else
        {
            Dog dog{ name };
            const Animal& ref{ dog };
            std::cout << dog.getName() << ": direct=" << dog.speak()
                      << " ref=" << ref.speak() << '\n';
        }
    }

    return 0;
}

