solution_code:
#include <iostream>
#include <string>

class Shape
{
    std::string m_name;

public:
    Shape(const std::string& name)
        : m_name{ name }
    {
    }

    const std::string& getName() const { return m_name; }
    std::string describe() const { return m_name + ": generic"; }
};

class Circle : public Shape
{
    int m_radius{};

public:
    Circle(const std::string& name, int radius)
        : Shape{ name }
        , m_radius{ radius }
    {
    }

    std::string describe() const
    {
        return getName() + ": circle r=" + std::to_string(m_radius);
    }
};

class Square : public Shape
{
    int m_side{};

public:
    Square(const std::string& name, int side)
        : Shape{ name }
        , m_side{ side }
    {
    }

    std::string describe() const
    {
        return getName() + ": square s=" + std::to_string(m_side);
    }
};

void report(const Shape& s)
{
    std::cout << s.describe() << '\n';
}

int main()
{
    int n{};
    std::cin >> n;

    for (int i{ 0 }; i < n; ++i)
    {
        std::string type{};
        std::string name{};
        std::cin >> type >> name;

        if (type == "circle")
        {
            int radius{};
            std::cin >> radius;
            Circle c{ name, radius };
            std::cout << c.describe() << '\n';
            report(c);
        }
        else
        {
            int side{};
            std::cin >> side;
            Square sq{ name, side };
            std::cout << sq.describe() << '\n';
            report(sq);
        }
    }

    return 0;
}
